-- Create "otel_forwarding_outbox" table
CREATE TABLE "otel_forwarding_outbox" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "organization_id" text NOT NULL,
  "kind" text NOT NULL,
  "content_type" text NOT NULL,
  "payload" bytea NOT NULL,
  "received_at" timestamptz NOT NULL DEFAULT clock_timestamp(),
  PRIMARY KEY ("id"),
  CONSTRAINT "otel_forwarding_outbox_organization_id_fkey" FOREIGN KEY ("organization_id") REFERENCES "organization_metadata" ("id") ON UPDATE NO ACTION ON DELETE CASCADE
);
-- Create index "otel_forwarding_outbox_organization_id_id_idx" to table: "otel_forwarding_outbox"
CREATE INDEX "otel_forwarding_outbox_organization_id_id_idx" ON "otel_forwarding_outbox" ("organization_id", "id");
-- Create "otel_forwarding_deliveries" table
CREATE TABLE "otel_forwarding_deliveries" (
  "outbox_id" bigint NOT NULL,
  "processed_at" timestamptz NULL,
  "dead_lettered" boolean NOT NULL DEFAULT false,
  "attempts" integer NOT NULL DEFAULT 0,
  "last_status_code" integer NULL,
  "last_error" text NULL,
  "created_at" timestamptz NOT NULL DEFAULT clock_timestamp(),
  "updated_at" timestamptz NOT NULL DEFAULT clock_timestamp(),
  PRIMARY KEY ("outbox_id"),
  CONSTRAINT "otel_forwarding_deliveries_outbox_id_fkey" FOREIGN KEY ("outbox_id") REFERENCES "otel_forwarding_outbox" ("id") ON UPDATE NO ACTION ON DELETE CASCADE
) WITH (fillfactor = 80, autovacuum_vacuum_scale_factor = 0.05, autovacuum_analyze_scale_factor = 0.05);
-- Create index "otel_forwarding_deliveries_pending_idx" to table: "otel_forwarding_deliveries"
CREATE INDEX "otel_forwarding_deliveries_pending_idx" ON "otel_forwarding_deliveries" ("outbox_id") WHERE ((processed_at IS NULL) AND (dead_lettered IS FALSE));
